<?phpnamespace App\Controller;use App\Entity\SysAdminOperation;use App\Entity\TypeCompte;use App\Form\TypeCompteType;use App\Repository\StructureRepository;use App\Repository\TypeCompteRepository;use DateTime;use DateTimeZone;use Sensio\Bundle\FrameworkExtraBundle\Configuration\Security;use Symfony\Bundle\FrameworkBundle\Controller\AbstractController;use Symfony\Component\HttpFoundation\JsonResponse;use Symfony\Component\HttpFoundation\Request;use Symfony\Component\HttpFoundation\Response;use Symfony\Component\Routing\Annotation\Route;class TypeCompteController extends AbstractController{    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/super-admin/type-comptes", name="type_compte_index", methods={"GET"})     * @param TypeCompteRepository $typeCompteRepository     * @return Response     */    public function index(TypeCompteRepository $typeCompteRepository): Response    {        return $this->render('type_compte/index.html.twig', [            'type_comptes' => $typeCompteRepository->findAll(),        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/type-comptes/new", name="type_compte_new", methods={"GET","POST"})     * @param Request $request     * @return Response     * @throws \Exception     */    public function new(Request $request): Response    {        $typeCompte = new TypeCompte();        $form = $this->createForm(TypeCompteType::class, $typeCompte);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->persist($typeCompte);            $entityManager->flush();            $this->addFlash('success', 'Le type de compte a été enregistré');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Enregistrement type de compte')                ->setUserAffected($typeCompte->getName());            $entityManager->persist($sysOp);            $entityManager->flush();            return $this->redirectToRoute('type_compte_index');        }        return $this->render('type_compte/new.html.twig', [            'type_compte' => $typeCompte,            'form' => $form->createView(),        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/type-comptes/{id}/edit", name="type_compte_edit", methods={"GET","POST"})     * @param Request $request     * @param TypeCompte $typeCompte     * @return Response     * @throws \Exception     */    public function edit(Request $request, TypeCompte $typeCompte): Response    {        $form = $this->createForm(TypeCompteType::class, $typeCompte);        $form->handleRequest($request);        if ($form->isSubmitted() && $form->isValid()) {            $this->getDoctrine()->getManager()->flush();            $this->addFlash('success', 'Le type de compte a été modifié');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Modification de type de compte')                ->setUserAffected($typeCompte->getName());            $entityManager->persist($sysOp);            $entityManager->flush();            return $this->redirectToRoute('type_compte_index');        }        return $this->render('type_compte/edit.html.twig', [            'type_compte' => $typeCompte,            'form' => $form->createView(),        ]);    }    /**     * @Security("is_granted('ROLE_SUPER_ADMIN') and user.getIsActived() and user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/super-admin/type-comptes/{id}", name="type_compte_delete", methods={"DELETE"})     * @param Request $request     * @param TypeCompte $typeCompte     * @return Response     * @throws \Exception     */    public function delete(Request $request, TypeCompte $typeCompte, StructureRepository $structureRepository): Response    {        if ($this->isCsrfTokenValid('delete' . $typeCompte->getId(), $request->request->get('_token'))) {            $entityManager = $this->getDoctrine()->getManager();            $entityManager->remove($typeCompte);            $entityManager->flush();            if ($typeCompte->getIsStructure()) {                foreach ($structureRepository->findAll() as $structure) {                    $entityManager->remove($structure);                    $entityManager->flush();                }            }            $this->addFlash('success', 'Le type de compte a été supprimé');            $sysOp = new SysAdminOperation();            $sysOp->setCreatedAt(new DateTime('now', new DateTimeZone('GMT')))                ->setKohUtilisateur($this->getUser())                ->setDescription('Suppression de type de compte')                ->setUserAffected($typeCompte->getName());            $entityManager->persist($sysOp);            $entityManager->flush();        }        return $this->redirectToRoute('type_compte_index');    }    /**     * @Route("/koh/type/compte/get/{id}", name="type_compte.get", methods={"GET"})     * @param TypeCompte $compte     * @return JsonResponse     */    public function getType(TypeCompte $compte): JsonResponse    {        $result = array(            'id' => $compte->getId(),            'libelle' => $compte->getName(),            'isStructure' => $compte->getIsStructure()        );        return new JsonResponse($result, 200);    }}